module RefModule(
    input clk,
    input rst,
    output [7:0] count
);

    reg [7:0] shift_reg;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst) begin
            shift_reg <= 8'b11111111;
        end else begin
            shift_reg <= {shift_reg[6:0], ~shift_reg[7]};
        end
    end

    assign count = shift_reg;

endmodule
